mapper.select:
SELECT a.*, c.category_name FROM asset_info a LEFT JOIN asset_category c ON a.category_id = c.id
AND a.asset_name LIKE CONCAT('%', #{assetName}, '%')
AND a.category_id = #{categoryId}
AND a.status = #{status}
ORDER BY a.create_time DESC

mapper.insert:
