    asset_code, asset_name, category_id, specifications, unit,
    purchase_date, purchase_price, supplier, warranty_period,
    status, location, responsible_person, description, image_url, create_by
) VALUES (
    #{assetCode}, #{assetName}, #{categoryId}, #{specifications}, #{unit},
    #{purchaseDate}, #{purchasePrice}, #{supplier}, #{warrantyPeriod},
    #{status}, #{location}, #{responsiblePerson}, #{description}, #{imageUrl}, #{createBy}
)

mapper.update:
UPDATE asset_info
asset_name = #{assetName}, category_id = #{categoryId}, specifications = #{specifications}, unit = #{unit}, purchase_date = #{purchaseDate}, purchase_price = #{purchasePrice}, supplier = #{supplier}, warranty_period = #{warrantyPeriod}, status = #{status}, location = #{location}, responsible_person = #{responsiblePerson}, description = #{description}, image_url = #{imageUrl},
